mapper.insert:
MERGE INTO MC_COW AS target USING ( SELECT #{auctDate} AS YYMMDD, #{marketCode} AS MarketCode, ISNULL(REPLACE(#{beefCnt, jdbcType=FLOAT},',',''), 0) AS H01, ISNULL(REPLACE(#{beefAmt, jdbcType=FLOAT},',',''), 0) AS H04, ISNULL(REPLACE(#{h05, jdbcType=FLOAT},',',''), 0) AS H05, ISNULL(REPLACE(#{cowCnt, jdbcType=FLOAT},',',''), 0) AS X01, ISNULL(REPLACE(#{cowAmt, jdbcType=FLOAT},',',''), 0) AS X04, ISNULL(REPLACE(#{x05, jdbcType=FLOAT},',',''), 0) AS X05, 0 AS H02, 0 AS H03, 0 AS X02, 0 AS X03 ) AS source ON (target.YYMMDD = source.YYMMDD AND target.MarketCode = source.MarketCode) WHEN MATCHED THEN UPDATE SET
X01 = source.X01, X04 = source.X04
WHEN NOT MATCHED THEN INSERT ( YYMMDD, MarketCode, H01, H04, H05, X01, X04, X05, H02, H03, X02, X03 ) VALUES ( source.YYMMDD, source.MarketCode, source.H01, source.H04, source.H05, source.X01, source.X04, source.X05, source.H02, source.H03, source.X02, source.X03 );
